begin;

create type public.inventory_stack_category as enum('consumable','chaos_card');
create type public.passive_effect_kind as enum('regeneration','gold','regeneration_full_set','gold_full_set');

create table public.equipment_definitions(
 id text primary key check(id~'^(common|rare|epic|legendary)_[a-z_]+_(helmet|armor|legs|boots)$'),
 display_name text not null,rarity text not null check(rarity in('common','rare','epic','legendary')),
 set_identity text not null,slot text not null check(slot in('helmet','armor','legs','boots')),
 effect_kind text not null,effect_value integer not null check(effect_value>=0),full_set_bonus integer not null check(full_set_bonus>=0),
 interval_seconds integer check(interval_seconds is null or interval_seconds in(3600,7200)),global_copy_limit integer check(global_copy_limit is null or global_copy_limit in(1,4)),
 image_key text not null unique,is_enabled boolean not null default true,
 unique(rarity,set_identity,slot),check((rarity='epic' and global_copy_limit=4)or(rarity='legendary' and global_copy_limit=1)or(rarity in('common','rare')and global_copy_limit is null))
);

with sets(rarity,set_name,effect_kind,full_bonus,interval_seconds)as(values
 ('common','regeneration','regeneration',1,3600),('common','damage','damage',0,null),('common','dodge','dodge',300,null),('common','potion','potion',500,null),
 ('rare','regeneration','regeneration',2,3600),('rare','damage','damage',300,null),('rare','protection','protection',600,null),('rare','hospital','hospital',2,null),
 ('epic','regeneration','regeneration',3,3600),('epic','damage','damage',300,null),('epic','gold','gold',1,7200),('epic','chest','chest',500,null),
 ('legendary','regeneration','regeneration',4,3600),('legendary','damage','damage',600,null),('legendary','thorns','thorns',600,null),('legendary','phoenix','phoenix',500,null)
),slots(slot)as(values('helmet'),('armor'),('legs'),('boots'))
insert into public.equipment_definitions(id,display_name,rarity,set_identity,slot,effect_kind,effect_value,full_set_bonus,interval_seconds,global_copy_limit,image_key)
select s.rarity||'_'||s.set_name||'_'||sl.slot,initcap(s.rarity||' '||s.set_name||' '||sl.slot),s.rarity,s.rarity||'_'||s.set_name,sl.slot,s.effect_kind,
 case
  when s.set_name='regeneration' then(case s.rarity||':'||sl.slot when'common:helmet'then 1 when'common:boots'then 1 when'common:legs'then 1 when'common:armor'then 2 when'rare:helmet'then 1 when'rare:boots'then 1 when'rare:legs'then 2 when'rare:armor'then 3 when'epic:helmet'then 2 when'epic:boots'then 2 when'epic:legs'then 3 when'epic:armor'then 4 when'legendary:helmet'then 3 when'legendary:boots'then 3 when'legendary:legs'then 4 else 6 end)
  when s.set_name='damage' then(case s.rarity||':'||sl.slot when'common:helmet'then 100 when'common:boots'then 100 when'common:legs'then 100 when'common:armor'then 200 when'rare:helmet'then 100 when'rare:boots'then 100 when'rare:legs'then 200 when'rare:armor'then 300 when'epic:helmet'then 200 when'epic:boots'then 200 when'epic:legs'then 300 when'epic:armor'then 500 when'legendary:helmet'then 300 when'legendary:boots'then 300 when'legendary:legs'then 500 else 800 end)
  when s.set_name in('dodge')then(case sl.slot when'helmet'then 100 when'boots'then 100 when'legs'then 200 else 300 end)
  when s.set_name='potion'then(case sl.slot when'helmet'then 100 when'boots'then 100 when'legs'then 300 else 500 end)
  when s.set_name in('protection','thorns')then(case sl.slot when'helmet'then 200 when'boots'then 200 when'legs'then 400 else 600 end)
  when s.set_name='hospital'then(case sl.slot when'helmet'then 4 when'boots'then 4 when'legs'then 8 else 12 end)
  when s.set_name='gold'then(case sl.slot when'helmet'then 1 when'boots'then 1 when'legs'then 2 else 3 end)
  when s.set_name='chest'then(case sl.slot when'helmet'then 200 when'boots'then 200 when'legs'then 600 else 1000 end)
  when s.set_name='phoenix'then(case sl.slot when'helmet'then 1000 when'boots'then 1000 when'legs'then 2500 else 5000 end)
 end,s.full_bonus,s.interval_seconds,case s.rarity when'epic'then 4 when'legendary'then 1 else null end,s.rarity||'_'||s.set_name||'_'||sl.slot
from sets s cross join slots sl;

create table public.stackable_item_definitions(category public.inventory_stack_category not null,id text not null,display_name text not null,rarity text not null check(rarity in('common','rare','epic','legendary')),image_key text not null,max_quantity integer not null default 10 check(max_quantity=10),primary key(category,id),unique(category,image_key));
insert into public.stackable_item_definitions values
('consumable','small_health_potion','Small Health Potion','common','small_health_potion',10),('consumable','xp_candy','XP Candy','common','xp_candy',10),('consumable','big_health_potion','Big Health Potion','rare','big_health_potion',10),('consumable','fortune_ticket','Fortune Ticket','rare','fortune_ticket',10),('consumable','experience_potion','Experience Potion','epic','experience_potion',10),('consumable','discharge_pill','Discharge Pill','epic','discharge_pill',10),('consumable','golden_hourglass','Golden Hourglass','legendary','golden_hourglass',10),
('chaos_card','smoke_cigarette','Smoke a Cigarette','common','smoke_cigarette',10),('chaos_card','double_sip','Double Sip','common','double_sip',10),('chaos_card','big_sip','Big Sip','rare','big_sip',10),('chaos_card','shot','Shot','rare','shot',10),('chaos_card','jagermeister_shot','Jägermeister Shot','epic','jagermeister_shot',10),('chaos_card','mirror','Mirror','epic','mirror',10),('chaos_card','finish_your_drink','Finish Your Drink','legendary','finish_your_drink',10);

create table public.equipment_global_supply(game_run_id uuid not null references public.game_runs(id),equipment_definition_id text not null references public.equipment_definitions(id),configured_maximum integer not null check(configured_maximum in(1,4)),claimed_count integer not null default 0 check(claimed_count>=0 and claimed_count<=configured_maximum),state_version bigint not null default 1,primary key(game_run_id,equipment_definition_id));
create table public.equipment_inventory_items(id uuid primary key default gen_random_uuid(),game_run_id uuid not null,owner_player_id uuid not null,equipment_definition_id text not null references public.equipment_definitions(id),source_type text not null,source_id text not null,acquired_at timestamptz not null default clock_timestamp(),cooldown_ends_at timestamptz,created_at timestamptz not null default clock_timestamp(),updated_at timestamptz not null default clock_timestamp(),foreign key(game_run_id,owner_player_id)references public.player_run_states(game_run_id,player_id),unique(game_run_id,source_type,source_id),unique(game_run_id,owner_player_id,id));
create index equipment_inventory_owner_idx on public.equipment_inventory_items(game_run_id,owner_player_id,equipment_definition_id);
create table public.equipped_equipment_slots(game_run_id uuid not null,player_id uuid not null,slot text not null check(slot in('helmet','armor','legs','boots')),inventory_item_id uuid not null unique,equipped_at timestamptz not null default clock_timestamp(),primary key(game_run_id,player_id,slot),foreign key(game_run_id,player_id,inventory_item_id)references public.equipment_inventory_items(game_run_id,owner_player_id,id));
create table public.stackable_inventory(game_run_id uuid not null,player_id uuid not null,category public.inventory_stack_category not null,item_id text not null,quantity integer not null check(quantity between 0 and 10),updated_at timestamptz not null default clock_timestamp(),primary key(game_run_id,player_id,category,item_id),foreign key(game_run_id,player_id)references public.player_run_states(game_run_id,player_id),foreign key(category,item_id)references public.stackable_item_definitions(category,id));
create table public.inventory_grant_sources(game_run_id uuid not null,player_id uuid not null,source_type text not null,source_id text not null,result jsonb not null,created_at timestamptz not null default clock_timestamp(),primary key(game_run_id,player_id,source_type,source_id));
create table public.passive_effect_cursors(id uuid primary key default gen_random_uuid(),game_run_id uuid not null,player_id uuid not null,inventory_item_id uuid,set_identity text,effect_kind public.passive_effect_kind not null,anchor_at timestamptz not null,cursor_at timestamptz not null,effective_remainder_seconds numeric(14,3) not null default 0 check(effective_remainder_seconds>=0 and effective_remainder_seconds<7200),next_check_at timestamptz not null,unique(game_run_id,player_id,inventory_item_id,effect_kind),foreign key(game_run_id,player_id)references public.player_run_states(game_run_id,player_id),foreign key(game_run_id,player_id,inventory_item_id)references public.equipment_inventory_items(game_run_id,owner_player_id,id),check((inventory_item_id is null)<>(set_identity is null)));
create unique index passive_effect_full_set_idx on public.passive_effect_cursors(game_run_id,player_id,set_identity,effect_kind)where inventory_item_id is null;
create index passive_effect_due_idx on public.passive_effect_cursors(game_run_id,player_id,next_check_at,id);
create table public.fortune_spin_entitlements(id uuid primary key default gen_random_uuid(),game_run_id uuid not null,player_id uuid not null,source_type text not null,source_id text not null,created_at timestamptz not null default clock_timestamp(),consumed_at timestamptz,unique(game_run_id,source_type,source_id),foreign key(game_run_id,player_id)references public.player_run_states(game_run_id,player_id));
alter table public.hospital_stays add constraint hospital_stays_run_player_id_key unique(game_run_id,player_id,id);
create table public.hospital_discharge_pill_uses(hospital_stay_id uuid primary key,game_run_id uuid not null,player_id uuid not null,used_at timestamptz not null default clock_timestamp(),foreign key(game_run_id,player_id,hospital_stay_id)references public.hospital_stays(game_run_id,player_id,id));

create or replace function public.inventory_assert_active(p_actor uuid,p_run uuid)returns public.player_run_states language plpgsql security definer set search_path=public,pg_temp as $$declare v_state public.player_run_states%rowtype;begin perform public.action_assert_live(p_run);select prs.* into v_state from public.player_run_states prs join public.players p on p.id=prs.player_id where prs.game_run_id=p_run and prs.player_id=p_actor and p.status='active' for update of prs;if not found then raise exception 'FORBIDDEN';end if;if v_state.gameplay_status='hospitalized'then raise exception 'PLAYER_HOSPITALIZED';end if;if v_state.gameplay_status<>'active'then raise exception 'LIFECYCLE_BLOCKED';end if;return v_state;end$$;

create or replace function public.inventory_refresh_full_set_cursors(p_run uuid,p_player uuid,p_at timestamptz)returns void language plpgsql security definer set search_path=public,pg_temp as $$begin delete from public.passive_effect_cursors c where c.game_run_id=p_run and c.player_id=p_player and c.inventory_item_id is null and not exists(select 1 from public.equipped_equipment_slots e join public.equipment_inventory_items i on i.id=e.inventory_item_id join public.equipment_definitions d on d.id=i.equipment_definition_id where e.game_run_id=p_run and e.player_id=p_player and d.set_identity=c.set_identity group by d.set_identity having count(*)=4);insert into public.passive_effect_cursors(game_run_id,player_id,set_identity,effect_kind,anchor_at,cursor_at,next_check_at)select p_run,p_player,d.set_identity,case d.effect_kind when'regeneration'then'regeneration_full_set'::public.passive_effect_kind else'gold_full_set'::public.passive_effect_kind end,p_at,p_at,p_at+make_interval(secs=>max(d.interval_seconds)) from public.equipped_equipment_slots e join public.equipment_inventory_items i on i.id=e.inventory_item_id join public.equipment_definitions d on d.id=i.equipment_definition_id where e.game_run_id=p_run and e.player_id=p_player and d.effect_kind in('regeneration','gold')group by d.set_identity,d.effect_kind having count(*)=4 on conflict do nothing;end$$;

create or replace function public.inventory_excluded_seconds(p_run uuid,p_player uuid,p_from timestamptz,p_to timestamptz,p_include_hospital boolean)returns numeric language sql stable security definer set search_path=public,pg_temp as $$with intervals as(select tstzrange(greatest(gp.started_at,p_from),least(coalesce(gp.ended_at,p_to),p_to),'[)') r from public.game_run_pauses gp where gp.game_run_id=p_run and gp.started_at<p_to and coalesce(gp.ended_at,p_to)>p_from union all select tstzrange(greatest(h.started_at,p_from),least(coalesce(h.released_at,p_to),p_to),'[)') from public.hospital_stays h where p_include_hospital and h.game_run_id=p_run and h.player_id=p_player and h.started_at<p_to and coalesce(h.released_at,p_to)>p_from),merged as(select range_agg(r) mr from intervals)select coalesce(sum(extract(epoch from upper(x)-lower(x))),0) from merged cross join lateral unnest(mr) x$$;

create or replace function public.process_passive_effects(p_run uuid,p_player uuid,p_limit integer default 50)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$begin raise exception'PASSIVE_PROCESSOR_NOT_READY';end$$;

create or replace function public.grant_equipment_instance(p_actor uuid,p_run uuid,p_player uuid,p_definition text,p_source_type text,p_source_id text,p_idempotency_key uuid,p_request_hash text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$
declare v_existing public.idempotency_records%rowtype;v_def public.equipment_definitions%rowtype;v_claimed integer;v_id uuid;v_result jsonb;v_now timestamptz:=clock_timestamp();
begin if p_request_hash!~'^[0-9a-f]{64}$'or p_source_type is null or btrim(p_source_type)=''or p_source_id is null or btrim(p_source_id)=''then raise exception'VALIDATION';end if;perform public.action_assert_live(p_run);if p_actor<>p_player and not exists(select 1 from public.players p where p.id=p_actor and p.role='admin'and p.status='active')then raise exception'FORBIDDEN';end if;
insert into public.idempotency_records(actor_player_id,game_run_id,command_name,idempotency_key,request_hash,expires_at)values(p_actor,p_run,'grant_equipment_instance',p_idempotency_key,p_request_hash,v_now+interval'24 hours')on conflict do nothing;select ir.* into v_existing from public.idempotency_records ir where ir.actor_player_id=p_actor and ir.command_name='grant_equipment_instance'and ir.idempotency_key=p_idempotency_key for update;if v_existing.game_run_id is distinct from p_run or v_existing.request_hash<>p_request_hash then raise exception'IDEMPOTENCY_CONFLICT';end if;if v_existing.status='completed'then return v_existing.result;end if;
select d.* into v_def from public.equipment_definitions d where d.id=p_definition and d.is_enabled for share;if not found then raise exception'ITEM_NOT_FOUND';end if;if v_def.global_copy_limit is not null then insert into public.equipment_global_supply(game_run_id,equipment_definition_id,configured_maximum)values(p_run,p_definition,v_def.global_copy_limit)on conflict do nothing;update public.equipment_global_supply s set claimed_count=s.claimed_count+1,state_version=s.state_version+1 where s.game_run_id=p_run and s.equipment_definition_id=p_definition and s.claimed_count<s.configured_maximum returning s.claimed_count into v_claimed;if not found then raise exception'EQUIPMENT_SUPPLY_EXHAUSTED';end if;end if;
insert into public.equipment_inventory_items(game_run_id,owner_player_id,equipment_definition_id,source_type,source_id)values(p_run,p_player,p_definition,p_source_type,p_source_id)returning id into v_id;perform public.core_record_event(p_run,p_player,'equipment_granted',jsonb_build_object('inventoryItemId',v_id,'definitionId',p_definition));v_result:=jsonb_build_object('inventoryItemId',v_id,'definitionId',p_definition,'status','granted');update public.idempotency_records ir set status='completed',result=v_result,completed_at=clock_timestamp()where ir.actor_player_id=p_actor and ir.command_name='grant_equipment_instance'and ir.idempotency_key=p_idempotency_key;return v_result;end$$;

create or replace function public.grant_stackable_item(p_actor uuid,p_run uuid,p_player uuid,p_category public.inventory_stack_category,p_item text,p_quantity integer,p_source_type text,p_source_id text,p_idempotency_key uuid,p_request_hash text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$
declare v_existing public.idempotency_records%rowtype;v_result jsonb;v_new integer;v_now timestamptz:=clock_timestamp();begin if p_quantity is null or p_quantity<1 or p_quantity>10 or p_request_hash!~'^[0-9a-f]{64}$'then raise exception'VALIDATION';end if;perform public.action_assert_live(p_run);if p_actor<>p_player and not exists(select 1 from public.players p where p.id=p_actor and p.role='admin'and p.status='active')then raise exception'FORBIDDEN';end if;if not exists(select 1 from public.stackable_item_definitions d where d.category=p_category and d.id=p_item)then raise exception'ITEM_NOT_FOUND';end if;
insert into public.idempotency_records(actor_player_id,game_run_id,command_name,idempotency_key,request_hash,expires_at)values(p_actor,p_run,'grant_stackable_item',p_idempotency_key,p_request_hash,v_now+interval'24 hours')on conflict do nothing;select ir.* into v_existing from public.idempotency_records ir where ir.actor_player_id=p_actor and ir.command_name='grant_stackable_item'and ir.idempotency_key=p_idempotency_key for update;if v_existing.game_run_id is distinct from p_run or v_existing.request_hash<>p_request_hash then raise exception'IDEMPOTENCY_CONFLICT';end if;if v_existing.status='completed'then return v_existing.result;end if;
insert into public.stackable_inventory(game_run_id,player_id,category,item_id,quantity)values(p_run,p_player,p_category,p_item,p_quantity)on conflict(game_run_id,player_id,category,item_id)do update set quantity=public.stackable_inventory.quantity+excluded.quantity,updated_at=v_now where public.stackable_inventory.quantity+excluded.quantity<=10 returning quantity into v_new;if v_new is null then raise exception'STACK_LIMIT_REACHED';end if;insert into public.inventory_grant_sources values(p_run,p_player,p_source_type,p_source_id,jsonb_build_object('category',p_category,'itemId',p_item,'quantity',p_quantity),v_now);perform public.core_record_event(p_run,p_player,'stackable_item_granted',jsonb_build_object('category',p_category,'itemId',p_item,'quantity',p_quantity));v_result:=jsonb_build_object('category',p_category,'itemId',p_item,'quantity',v_new);update public.idempotency_records ir set status='completed',result=v_result,completed_at=clock_timestamp()where ir.actor_player_id=p_actor and ir.command_name='grant_stackable_item'and ir.idempotency_key=p_idempotency_key;return v_result;end$$;

create or replace function public.equip_equipment_item(p_actor uuid,p_run uuid,p_item uuid,p_replace uuid,p_idempotency_key uuid,p_request_hash text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$
declare v_existing public.idempotency_records%rowtype;v_new public.equipment_inventory_items%rowtype;v_old public.equipment_inventory_items%rowtype;v_slot text;v_now timestamptz:=clock_timestamp();v_result jsonb;begin perform public.inventory_assert_active(p_actor,p_run);if p_request_hash!~'^[0-9a-f]{64}$'then raise exception'VALIDATION';end if;insert into public.idempotency_records(actor_player_id,game_run_id,command_name,idempotency_key,request_hash,expires_at)values(p_actor,p_run,'equip_equipment_item',p_idempotency_key,p_request_hash,v_now+interval'24 hours')on conflict do nothing;select ir.* into v_existing from public.idempotency_records ir where ir.actor_player_id=p_actor and ir.command_name='equip_equipment_item'and ir.idempotency_key=p_idempotency_key for update;if v_existing.request_hash<>p_request_hash or v_existing.game_run_id is distinct from p_run then raise exception'IDEMPOTENCY_CONFLICT';end if;if v_existing.status='completed'then return v_existing.result;end if;
perform 1 from public.equipment_inventory_items i where i.id in(p_item,p_replace)order by i.id for update;select i.* into v_new from public.equipment_inventory_items i where i.id=p_item and i.game_run_id=p_run and i.owner_player_id=p_actor;if not found then raise exception'ITEM_NOT_OWNED';end if;if v_new.cooldown_ends_at>v_now then raise exception'EQUIPMENT_COOLDOWN_ACTIVE';end if;select d.slot into v_slot from public.equipment_definitions d where d.id=v_new.equipment_definition_id;if exists(select 1 from public.equipped_equipment_slots e where e.inventory_item_id=p_item)then raise exception'ITEM_ALREADY_EQUIPPED';end if;
if p_replace is null then if exists(select 1 from public.equipped_equipment_slots e where e.game_run_id=p_run and e.player_id=p_actor and e.slot=v_slot)then raise exception'SLOT_OCCUPIED';end if;else select i.* into v_old from public.equipment_inventory_items i join public.equipped_equipment_slots e on e.inventory_item_id=i.id where i.id=p_replace and e.game_run_id=p_run and e.player_id=p_actor and e.slot=v_slot for update of e;if not found then raise exception'REPLACEMENT_MISMATCH';end if;if v_old.cooldown_ends_at>v_now then raise exception'EQUIPMENT_COOLDOWN_ACTIVE';end if;perform public.process_passive_effects(p_run,p_actor,100);delete from public.passive_effect_cursors c where c.inventory_item_id=p_replace;delete from public.equipped_equipment_slots e where e.inventory_item_id=p_replace;update public.equipment_inventory_items i set cooldown_ends_at=v_now+interval'15 minutes',updated_at=v_now where i.id=p_replace;end if;
insert into public.equipped_equipment_slots(game_run_id,player_id,slot,inventory_item_id,equipped_at)values(p_run,p_actor,v_slot,p_item,v_now);update public.equipment_inventory_items i set cooldown_ends_at=v_now+interval'15 minutes',updated_at=v_now where i.id=p_item;insert into public.passive_effect_cursors(game_run_id,player_id,inventory_item_id,effect_kind,anchor_at,cursor_at,next_check_at)select p_run,p_actor,p_item,case d.effect_kind when'regeneration'then'regeneration'::public.passive_effect_kind else'gold'::public.passive_effect_kind end,v_now,v_now,v_now+make_interval(secs=>d.interval_seconds) from public.equipment_definitions d where d.id=v_new.equipment_definition_id and d.effect_kind in('regeneration','gold');perform public.inventory_refresh_full_set_cursors(p_run,p_actor,v_now);perform public.core_record_event(p_run,p_actor,case when p_replace is null then'equipment_equipped'else'equipment_replaced'end,jsonb_build_object('inventoryItemId',p_item,'replacedItemId',p_replace,'slot',v_slot));v_result:=jsonb_build_object('inventoryItemId',p_item,'replacedItemId',p_replace,'slot',v_slot,'cooldownEndsAt',v_now+interval'15 minutes');update public.idempotency_records ir set status='completed',result=v_result,completed_at=clock_timestamp()where ir.actor_player_id=p_actor and ir.command_name='equip_equipment_item'and ir.idempotency_key=p_idempotency_key;return v_result;end$$;

create or replace function public.unequip_equipment_item(p_actor uuid,p_run uuid,p_item uuid,p_idempotency_key uuid,p_request_hash text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare v_existing public.idempotency_records%rowtype;v_item public.equipment_inventory_items%rowtype;v_now timestamptz:=clock_timestamp();v_result jsonb;begin perform public.inventory_assert_active(p_actor,p_run);if p_request_hash!~'^[0-9a-f]{64}$'then raise exception'VALIDATION';end if;insert into public.idempotency_records(actor_player_id,game_run_id,command_name,idempotency_key,request_hash,expires_at)values(p_actor,p_run,'unequip_equipment_item',p_idempotency_key,p_request_hash,v_now+interval'24 hours')on conflict do nothing;select ir.* into v_existing from public.idempotency_records ir where ir.actor_player_id=p_actor and ir.command_name='unequip_equipment_item'and ir.idempotency_key=p_idempotency_key for update;if v_existing.request_hash<>p_request_hash then raise exception'IDEMPOTENCY_CONFLICT';end if;if v_existing.status='completed'then return v_existing.result;end if;select i.* into v_item from public.equipment_inventory_items i join public.equipped_equipment_slots e on e.inventory_item_id=i.id where i.id=p_item and i.game_run_id=p_run and i.owner_player_id=p_actor for update of i,e;if not found then raise exception'ITEM_NOT_EQUIPPED';end if;if v_item.cooldown_ends_at>v_now then raise exception'EQUIPMENT_COOLDOWN_ACTIVE';end if;perform public.process_passive_effects(p_run,p_actor,100);delete from public.equipped_equipment_slots e where e.inventory_item_id=p_item;delete from public.passive_effect_cursors c where c.inventory_item_id=p_item;perform public.inventory_refresh_full_set_cursors(p_run,p_actor,v_now);update public.equipment_inventory_items i set cooldown_ends_at=v_now+interval'15 minutes',updated_at=v_now where i.id=p_item;perform public.core_record_event(p_run,p_actor,'equipment_unequipped',jsonb_build_object('inventoryItemId',p_item));v_result:=jsonb_build_object('inventoryItemId',p_item,'status','unequipped','cooldownEndsAt',v_now+interval'15 minutes');update public.idempotency_records ir set status='completed',result=v_result,completed_at=clock_timestamp()where ir.actor_player_id=p_actor and ir.command_name='unequip_equipment_item'and ir.idempotency_key=p_idempotency_key;return v_result;end$$;

create or replace function public.get_inventory_snapshot(p_run uuid,p_player uuid)returns jsonb language sql stable security definer set search_path=public,pg_temp as $$select jsonb_build_object('serverNow',clock_timestamp(),'equipment',coalesce((select jsonb_agg(jsonb_build_object('inventoryItemId',i.id,'definitionId',i.equipment_definition_id,'cooldownEndsAt',i.cooldown_ends_at,'slot',e.slot,'equipped',e.inventory_item_id is not null)order by i.acquired_at,i.id)from public.equipment_inventory_items i left join public.equipped_equipment_slots e on e.inventory_item_id=i.id where i.game_run_id=p_run and i.owner_player_id=p_player),'[]'::jsonb),'stacks',coalesce((select jsonb_agg(jsonb_build_object('category',s.category,'itemId',s.item_id,'quantity',s.quantity)order by s.category,s.item_id)from public.stackable_inventory s where s.game_run_id=p_run and s.player_id=p_player),'[]'::jsonb))$$;

create or replace function public.use_inventory_consumable(p_actor uuid,p_run uuid,p_item text,p_idempotency_key uuid,p_request_hash text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$
declare v_existing public.idempotency_records%rowtype;v_state public.player_run_states%rowtype;v_stack public.stackable_inventory%rowtype;v_now timestamptz:=clock_timestamp();v_base integer;v_bonus integer:=0;v_amount integer;v_need integer;v_changed integer;v_result jsonb;
begin v_state:=public.inventory_assert_active(p_actor,p_run);if p_request_hash!~'^[0-9a-f]{64}$'then raise exception'VALIDATION';end if;insert into public.idempotency_records(actor_player_id,game_run_id,command_name,idempotency_key,request_hash,expires_at)values(p_actor,p_run,'use_inventory_consumable',p_idempotency_key,p_request_hash,v_now+interval'24 hours')on conflict do nothing;select ir.* into v_existing from public.idempotency_records ir where ir.actor_player_id=p_actor and ir.command_name='use_inventory_consumable'and ir.idempotency_key=p_idempotency_key for update;if v_existing.game_run_id is distinct from p_run or v_existing.request_hash<>p_request_hash then raise exception'IDEMPOTENCY_CONFLICT';end if;if v_existing.status='completed'then return v_existing.result;end if;select s.* into v_stack from public.stackable_inventory s where s.game_run_id=p_run and s.player_id=p_actor and s.category='consumable'and s.item_id=p_item and s.quantity>0 for update;if not found then raise exception'ITEM_NOT_OWNED';end if;
if p_item in('small_health_potion','big_health_potion')then v_base:=case p_item when'small_health_potion'then 25 else 60 end;select coalesce(sum(d.effect_value),0)+case when count(*)=4 then max(d.full_set_bonus)else 0 end into v_bonus from public.equipped_equipment_slots e join public.equipment_inventory_items i on i.id=e.inventory_item_id join public.equipment_definitions d on d.id=i.equipment_definition_id where e.game_run_id=p_run and e.player_id=p_actor and d.set_identity='common_potion';v_amount:=ceil(v_base*(10000+v_bonus)/10000.0);if v_state.current_hp>=100+(v_state.current_level-1)*5 then raise exception'FULL_HP';end if;v_amount:=least(v_amount,100+(v_state.current_level-1)*5-v_state.current_hp);update public.player_run_states prs set current_hp=prs.current_hp+v_amount,updated_at=v_now where prs.game_run_id=p_run and prs.player_id=p_actor;v_result:=jsonb_build_object('itemId',p_item,'hpRestored',v_amount);
elsif p_item in('xp_candy','experience_potion')then if v_state.current_level=40 then raise exception'LEVEL_CAP';end if;select t.requirement into v_need from public.level_xp_thresholds t where t.level=v_state.current_level;v_amount:=ceil(v_need*(case p_item when'xp_candy'then .05 else .30 end));perform public.core_mutate_xp(p_actor,p_run,p_actor,v_amount,'consumable',p_idempotency_key::text,extensions.gen_random_uuid(),encode(extensions.digest(convert_to('consumable-xp:'||p_idempotency_key::text,'UTF8'),'sha256'::text),'hex'));v_result:=jsonb_build_object('itemId',p_item,'xpRequested',v_amount);
elsif p_item='fortune_ticket'then insert into public.fortune_spin_entitlements(game_run_id,player_id,source_type,source_id)values(p_run,p_actor,'fortune_ticket',p_idempotency_key::text);v_result:=jsonb_build_object('itemId',p_item,'fortuneEntitlementCreated',true);
elsif p_item='golden_hourglass'then update public.action_cooldowns c set cooldown_ends_at=v_now,updated_at=v_now from public.action_definitions d where d.id=c.action_id and c.game_run_id=p_run and c.player_id=p_actor and c.cooldown_ends_at>v_now and d.is_enabled and d.hourglass_resettable;get diagnostics v_changed=row_count;if v_changed=0 then raise exception'NO_ELIGIBLE_COOLDOWN';end if;v_result:=jsonb_build_object('itemId',p_item,'cooldownsReset',v_changed);
elsif p_item='discharge_pill'then raise exception'HOSPITAL_ONLY';else raise exception'ITEM_NOT_FOUND';end if;
update public.stackable_inventory s set quantity=s.quantity-1,updated_at=v_now where s.game_run_id=p_run and s.player_id=p_actor and s.category='consumable'and s.item_id=p_item;perform public.core_record_event(p_run,p_actor,'consumable_used',v_result);v_result:=v_result||jsonb_build_object('remainingQuantity',v_stack.quantity-1);update public.idempotency_records ir set status='completed',result=v_result,completed_at=clock_timestamp()where ir.actor_player_id=p_actor and ir.command_name='use_inventory_consumable'and ir.idempotency_key=p_idempotency_key;return v_result;end$$;

create or replace function public.process_passive_effects(p_run uuid,p_player uuid,p_limit integer default 50)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$
declare v_now timestamptz:=clock_timestamp();v_cursor public.passive_effect_cursors%rowtype;v_def public.equipment_definitions%rowtype;v_effective numeric;v_total numeric;v_interval integer;v_intervals integer;v_amount integer;v_processed integer:=0;v_max integer;
begin if p_limit<1 or p_limit>100 then raise exception'VALIDATION';end if;perform public.action_assert_live(p_run);
for v_cursor in select c.* from public.passive_effect_cursors c where c.game_run_id=p_run and c.player_id=p_player and c.next_check_at<=v_now order by c.next_check_at,c.id for update skip locked limit p_limit loop
if v_cursor.inventory_item_id is null then select d.* into v_def from public.equipment_definitions d where d.set_identity=v_cursor.set_identity limit 1;v_def.effect_value:=v_def.full_set_bonus;else select d.* into v_def from public.equipment_inventory_items i join public.equipped_equipment_slots e on e.inventory_item_id=i.id join public.equipment_definitions d on d.id=i.equipment_definition_id where i.id=v_cursor.inventory_item_id;if not found then delete from public.passive_effect_cursors c where c.id=v_cursor.id;continue;end if;end if;
v_interval:=case when v_cursor.effect_kind in('gold','gold_full_set')then 7200 else 3600 end;v_effective:=greatest(0,extract(epoch from(v_now-v_cursor.cursor_at))-public.inventory_excluded_seconds(p_run,p_player,v_cursor.cursor_at,v_now,v_cursor.effect_kind in('regeneration','regeneration_full_set')));v_total:=v_cursor.effective_remainder_seconds+v_effective;v_intervals:=floor(v_total/v_interval);v_amount:=v_intervals*v_def.effect_value;
if v_intervals>0 then if v_cursor.effect_kind in('gold','gold_full_set')then perform public.core_change_coins(p_player,p_run,p_player,v_amount,'passive_gold',v_cursor.id::text||':'||v_cursor.cursor_at::text,extensions.gen_random_uuid(),encode(extensions.digest(convert_to('passive-gold:'||v_cursor.id::text||':'||v_cursor.cursor_at::text,'UTF8'),'sha256'::text),'hex'));else select 100+(prs.current_level-1)*5 into v_max from public.player_run_states prs where prs.game_run_id=p_run and prs.player_id=p_player for update;update public.player_run_states prs set current_hp=least(v_max,prs.current_hp+v_amount),updated_at=v_now where prs.game_run_id=p_run and prs.player_id=p_player;perform public.core_record_event(p_run,p_player,'passive_regeneration_processed',jsonb_build_object('cursorId',v_cursor.id,'intervals',v_intervals,'requestedHp',v_amount));end if;v_processed:=v_processed+1;end if;
update public.passive_effect_cursors c set cursor_at=v_now,effective_remainder_seconds=v_total%v_interval,next_check_at=v_now+make_interval(secs=>v_interval-(v_total%v_interval))where c.id=v_cursor.id;end loop;return jsonb_build_object('processed',v_processed,'serverNow',v_now);end$$;

create or replace function public.use_discharge_pill(p_actor uuid,p_run uuid,p_idempotency_key uuid,p_request_hash text)returns jsonb language plpgsql security definer set search_path=public,pg_temp as $$declare v_now timestamptz:=clock_timestamp();v_existing public.idempotency_records%rowtype;v_stay public.hospital_stays%rowtype;v_remaining integer;v_released boolean;v_result jsonb;begin perform public.action_assert_live(p_run);if p_request_hash!~'^[0-9a-f]{64}$'then raise exception'VALIDATION';end if;insert into public.idempotency_records(actor_player_id,game_run_id,command_name,idempotency_key,request_hash,expires_at)values(p_actor,p_run,'use_discharge_pill',p_idempotency_key,p_request_hash,v_now+interval'24 hours')on conflict do nothing;select ir.* into v_existing from public.idempotency_records ir where ir.actor_player_id=p_actor and ir.command_name='use_discharge_pill'and ir.idempotency_key=p_idempotency_key for update;if v_existing.game_run_id is distinct from p_run or v_existing.request_hash<>p_request_hash then raise exception'IDEMPOTENCY_CONFLICT';end if;if v_existing.status='completed'then return v_existing.result;end if;select h.* into v_stay from public.hospital_stays h where h.game_run_id=p_run and h.player_id=p_actor and h.released_at is null for update;if not found then raise exception'NOT_HOSPITALIZED';end if;if exists(select 1 from public.hospital_discharge_pill_uses u where u.hospital_stay_id=v_stay.id)then raise exception'DISCHARGE_ALREADY_USED';end if;perform 1 from public.stackable_inventory s where s.game_run_id=p_run and s.player_id=p_actor and s.category='consumable'and s.item_id='discharge_pill'and s.quantity>0 for update;if not found then raise exception'ITEM_NOT_OWNED';end if;insert into public.hospital_discharge_pill_uses(hospital_stay_id,game_run_id,player_id,used_at)values(v_stay.id,p_run,p_actor,v_now);update public.stackable_inventory s set quantity=s.quantity-1,updated_at=v_now where s.game_run_id=p_run and s.player_id=p_actor and s.category='consumable'and s.item_id='discharge_pill'returning s.quantity into v_remaining;v_released:=v_stay.hospital_until-interval'20 minutes'<=v_now;update public.hospital_stays h set hospital_until=h.hospital_until-interval'20 minutes',released_at=case when v_released then v_now else h.released_at end where h.id=v_stay.id;if v_released then update public.player_run_states prs set gameplay_status='active',current_hp=ceil((100+(prs.current_level-1)*5)*.75),state_version=state_version+1,updated_at=v_now where prs.game_run_id=p_run and prs.player_id=p_actor;end if;v_result:=jsonb_build_object('itemId','discharge_pill','hospitalStayId',v_stay.id,'hospitalUntil',v_stay.hospital_until-interval'20 minutes','released',v_released,'remainingQuantity',v_remaining);perform public.core_record_event(p_run,p_actor,'discharge_pill_used',v_result);update public.idempotency_records ir set status='completed',result=v_result,completed_at=v_now where ir.actor_player_id=p_actor and ir.command_name='use_discharge_pill'and ir.idempotency_key=p_idempotency_key;return v_result;end$$;

do$$declare n text;begin foreach n in array array['equipment_definitions','stackable_item_definitions','equipment_global_supply','equipment_inventory_items','equipped_equipment_slots','stackable_inventory','inventory_grant_sources','passive_effect_cursors','fortune_spin_entitlements','hospital_discharge_pill_uses']loop execute format('alter table public.%I enable row level security',n);execute format('alter table public.%I force row level security',n);execute format('revoke all on table public.%I from public,anon,authenticated',n);end loop;end$$;
revoke all on function public.inventory_assert_active(uuid,uuid),public.inventory_refresh_full_set_cursors(uuid,uuid,timestamptz),public.inventory_excluded_seconds(uuid,uuid,timestamptz,timestamptz,boolean),public.grant_equipment_instance(uuid,uuid,uuid,text,text,text,uuid,text),public.grant_stackable_item(uuid,uuid,uuid,public.inventory_stack_category,text,integer,text,text,uuid,text),public.equip_equipment_item(uuid,uuid,uuid,uuid,uuid,text),public.unequip_equipment_item(uuid,uuid,uuid,uuid,text),public.get_inventory_snapshot(uuid,uuid),public.use_inventory_consumable(uuid,uuid,text,uuid,text),public.process_passive_effects(uuid,uuid,integer),public.use_discharge_pill(uuid,uuid,uuid,text)from public,anon,authenticated;
grant execute on function public.grant_equipment_instance(uuid,uuid,uuid,text,text,text,uuid,text),public.grant_stackable_item(uuid,uuid,uuid,public.inventory_stack_category,text,integer,text,text,uuid,text),public.equip_equipment_item(uuid,uuid,uuid,uuid,uuid,text),public.unequip_equipment_item(uuid,uuid,uuid,uuid,text),public.get_inventory_snapshot(uuid,uuid),public.use_inventory_consumable(uuid,uuid,text,uuid,text),public.process_passive_effects(uuid,uuid,integer),public.use_discharge_pill(uuid,uuid,uuid,text)to service_role;

commit;
